import java.io.*;
import java.util.*;

public class Main {
    static class Edge {
        int to;
        long w;
        Edge(int to, long w) { this.to = to; this.w = w; }
    }
    static class Node {
        int v;
        long dist;
        Node(int v, long dist) { this.v = v; this.dist = dist; }
    }
    static class FastScanner {
        private final InputStream in;
        private final byte[] buffer = new byte[1 << 16];
        private int ptr = 0, len = 0;
        FastScanner(InputStream in) { this.in = in; }
        private int read() throws IOException {
            if (ptr >= len) {
                len = in.read(buffer);
                ptr = 0;
                if (len <= 0) return -1;
            }
            return buffer[ptr++];
        }
        Integer nextInt() throws IOException {
            int c, sign = 1, val = 0;
            do {
                c = read();
                if (c == -1) return null;
            } while (c <= ' ');
            if (c == '-') { sign = -1; c = read(); }
            while (c > ' ') {
                val = val * 10 + (c - '0');
                c = read();
            }
            return val * sign;
        }
        Long nextLong() throws IOException {
            int c, sign = 1;
            long val = 0;
            do {
                c = read();
                if (c == -1) return null;
            } while (c <= ' ');
            if (c == '-') { sign = -1; c = read(); }
            while (c > ' ') {
                val = val * 10 + (c - '0');
                c = read();
            }
            return val * sign;
        }
    }
    static final long INF = Long.MAX_VALUE / 4;
    public static void main(String[] args) throws Exception {
        FastScanner fs = new FastScanner(System.in);
        Integer tObj = fs.nextInt();
        if (tObj == null) return; // no input
        int T = tObj;
        StringBuilder sb = new StringBuilder();
        while (T-- > 0) {
            int N = fs.nextInt();
            int M = fs.nextInt();
            int S = fs.nextInt() - 1;
            int V = fs.nextInt() - 1;
            int Tt = fs.nextInt() - 1;
            @SuppressWarnings("unchecked")
            List<Edge>[] adj = new ArrayList[N];
            for (int i = 0; i < N; i++) adj[i] = new ArrayList<>();
            for (int i = 0; i < M; i++) {
                int a = fs.nextInt() - 1;
                int b = fs.nextInt() - 1;
                long c = fs.nextLong();
                adj[a].add(new Edge(b, c));
                adj[b].add(new Edge(a, c));
            }
            int[] terminals = new int[]{S, V, Tt};
            int K = 3;
            int fullMask = (1 << K) - 1; // 7
            long[][] dp = new long[fullMask + 1][N];
            for (int mask = 0; mask <= fullMask; mask++) {
                Arrays.fill(dp[mask], INF);
            }
            for (int i = 0; i < K; i++) {
                dp[1 << i][terminals[i]] = 0;
            }
            // DP over subsets
            for (int mask = 1; mask <= fullMask; mask++) {
                // combine smaller subsets
                for (int sub = (mask - 1) & mask; sub > 0; sub = (sub - 1) & mask) {
                    int other = mask ^ sub;
                    if (other == 0) continue;
                    for (int v = 0; v < N; v++) {
                        long cand = dp[sub][v] + dp[other][v];
                        if (cand < dp[mask][v]) dp[mask][v] = cand;
                    }
                }
                // Dijkstra to propagate distances for this mask
                PriorityQueue<Node> pq = new PriorityQueue<>(Comparator.comparingLong(a -> a.dist));
                for (int v = 0; v < N; v++) {
                    if (dp[mask][v] < INF) {
                        pq.offer(new Node(v, dp[mask][v]));
                    }
                }
                while (!pq.isEmpty()) {
                    Node cur = pq.poll();
                    if (cur.dist != dp[mask][cur.v]) continue;
                    for (Edge e : adj[cur.v]) {
                        long nd = cur.dist + e.w;
                        if (nd < dp[mask][e.to]) {
                            dp[mask][e.to] = nd;
                            pq.offer(new Node(e.to, nd));
                        }
                    }
                }
            }
            long ans = INF;
            for (int v = 0; v < N; v++) {
                if (dp[fullMask][v] < ans) ans = dp[fullMask][v];
            }
            sb.append(ans).append('\n');
        }
        System.out.print(sb.toString());
    }
}

